import React, { useState, useRef, useEffect } from "react";
import { motion } from "framer-motion";

const MusicToggle = () => {
  const [playing, setPlaying] = useState(false);
  const audioRef = useRef(null);

  // Using a royalty-free romantic instrumental from a public source
  // Replace with your own audio file path in /public/music.mp3
  const audioSrc = "/music.mp3";

  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.volume = 0.4;
      audioRef.current.loop = true;
    }
  }, []);

  const toggle = () => {
    if (!audioRef.current) return;
    if (playing) {
      audioRef.current.pause();
    } else {
      audioRef.current.play().catch(() => {});
    }
    setPlaying(!playing);
  };

  return (
    <>
      <audio ref={audioRef} src={audioSrc} preload="none" />
      <motion.button
        onClick={toggle}
        className="music-btn"
        whileHover={{ scale: 1.1 }}
        whileTap={{ scale: 0.9 }}
        title={playing ? "Pause Music" : "Play Music"}
        aria-label={playing ? "Pause background music" : "Play background music"}
      >
        {playing ? (
          <motion.div
            className="flex gap-0.5 items-end h-5"
            initial={false}
          >
            {[1, 2, 3].map((i) => (
              <motion.div
                key={i}
                className="w-1 bg-dark-bg rounded-full"
                animate={{ height: ["40%", "100%", "40%"] }}
                transition={{ duration: 0.6, repeat: Infinity, delay: i * 0.15 }}
              />
            ))}
          </motion.div>
        ) : (
          <span className="text-dark-bg text-lg">♪</span>
        )}
      </motion.button>
    </>
  );
};

export default MusicToggle;
